    emit_init();
    emit_str("hello");
    emit_nl();
    emit_line("world");
    uart_putstr("  len=");
    print_int(emit_length());
    uart_putchar(10);
    uart_putstr("  buf: ");
    uart_putstr(emit_output());

    /* Test 2: emit_int */
    uart_puts("--- emit_int ---");
    emit_init();
    emit_int(0);
    emit_char(32);
    emit_int(42);
    emit_char(32);
    emit_int(12345);
    emit_char(32);
    emit_int(-7);
    uart_putstr("  ");
    uart_puts(emit_output());

    /* Test 3: label generation */
    uart_puts("--- labels ---");
