    uart_putstr(" l1=");
    print_int(l1);
    uart_putstr(" l2=");
    print_int(l2);
    uart_putchar(10);
    emit_label(l0);
    emit_label(l1);
    uart_putstr("  ");
    uart_putstr(emit_output());

    /* Test 4: named labels */
    uart_puts("--- named labels ---");
    emit_init();
    emit_named_label("main");
    emit_named_label("foo");
    uart_putstr(emit_output());

    /* Test 5: instructions */
    uart_puts("--- instructions ---");
    emit_init();
    emit_instr0("nop");
    emit_instr1("push", "fp");
    emit_instr2("mov", "fp", "sp");
    emit_instr("jmp     (r1)");
    uart_putstr(emit_output());

    /* Test 6: comments */
    uart_puts("--- comments ---");
    emit_init();
    emit_comment("PL/SW source line");
    emit_source_line("x = y + 1;");
    uart_putstr(emit_output());

    /* Test 7: section switching */
    uart_puts("--- sections ---");
